avg_map = {r['business_ref']: float(r['avg_rating']) for r in review_avgs}

def extract_categories(desc):
    if not desc:
        return []
    # Try to capture the part listing categories after common phrases
    m = re.search(r'offers.*?(?:in the fields of|in the fields of the|in the fields|in|including|for|offers a range of services|offers a diverse range of services)\s*(.*)', desc, flags=re.I)
    if m:
        tail = m.group(1)
    else:
        m2 = re.search(r'offers\s*(.*)', desc, flags=re.I)
        if m2:
            tail = m2.group(1)
        else:
            parts = desc.split(',')
            if len(parts) > 1:
                tail = parts[-1]
            else:
                return []
    tail = tail.split('.')[0]
    tail = tail.replace(' and ', ', ')
    items = [it.strip().strip('.') for it in re.split(r',|&', tail) if it.strip()]
    # Filter obvious non-categories
    filtered = []
    for it in items:
        it_clean = re.sub(r"^(a |the )", '', it, flags=re.I).strip()
        if len(it_clean) < 2:
            continue
        filtered.append(it_clean)
    return filtered

from collections import Counter, defaultdict
cat_counts = Counter()
cat_to_biz = defaultdict(list)

for b in biz_records:
    bid = b.get('business_id')
    desc = b.get('description','')
    cats = extract_categories(desc)
    # if categories empty, also check if there's an explicit 'categories' field
    if not cats and 'categories' in b and b.get('categories'):
        raw = b.get('categories')
        if isinstance(raw, str):
            items = [it.strip() for it in raw.split(',') if it.strip()]
            cats = items
    for c in cats:
        cat_counts[c] += 1
        cat_to_biz[c].append(bid)

if not cat_counts:
    result = {"category": None, "business_count": 0, "average_rating": None}
else:
    max_count = max(cat_counts.values())
    top_cats = [c for c,v in cat_counts.items() if v==max_count]
    top_cats.sort()
    top_cat = top_cats[0]
    ratings = []
    for bid in cat_to_biz[top_cat]:
        bref = bid.replace('businessid_','businessref_')
        if bref in avg_map:
            ratings.append(avg_map[bref])
    avg_rating = None
    if ratings:
        avg_rating = sum(ratings)/len(ratings)
    result = {"category": top_cat, "business_count": max_count, "average_rating": avg_rating}

print("__RESULT__:")
print(json.dumps(result))"}
